    public Object parseTicker(Object ticker, Object... optionalArgs)
    {
        //
        //     {
        //         "high":"0.01951",
        //         "low":"0.01877",
        //         "vol_eth":"39.38839319",
        //         "vol_btc":"0.75320886",
        //         "last":"0.01896",
        //         "buy":"0.01896",
        //         "sell":"0.019",
        //         "server_time":1565248908
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object symbol = this.safeSymbol(null, market);
        Object timestamp = this.safeTimestamp(ticker, "server_time");
        Object baseVolume = Helpers.add("vol_", this.safeStringLower(market, "baseId"));
        Object quoteVolume = Helpers.add("vol_", this.safeStringLower(market, "quoteId"));
        Object last = this.safeString(ticker, "last");
        return this.safeTicker(new java.util.HashMap<String, Object>() {{
            put( "symbol", symbol );
            put( "timestamp", timestamp );
            put( "datetime", IndodaxCore.this.iso8601(timestamp) );
            put( "high", IndodaxCore.this.safeString(ticker, "high") );
            put( "low", IndodaxCore.this.safeString(ticker, "low") );
            put( "bid", IndodaxCore.this.safeString(ticker, "buy") );
            put( "bidVolume", null );
            put( "ask", IndodaxCore.this.safeString(ticker, "sell") );
            put( "askVolume", null );
            put( "vwap", null );
            put( "open", null );
            put( "close", last );
            put( "last", last );
            put( "previousClose", null );
            put( "change", null );
            put( "percentage", null );
            put( "average", null );
            put( "baseVolume", IndodaxCore.this.safeString(ticker, baseVolume) );
            put( "quoteVolume", IndodaxCore.this.safeString(ticker, quoteVolume) );
            put( "info", ticker );
        }}, market);
    }

