    public Object parseOrder(Object order, Object... optionalArgs)
    {
        //
        //     {
        //         "order_id": "12345",
        //         "submit_time": "1392228122",
        //         "price": "8000000",
        //         "type": "sell",
        //         "order_ltc": "100000000",
        //         "remain_ltc": "100000000"
        //     }
        //
        // market closed orders - note that the price is very high
        // and does not reflect actual price the order executed at
        //
        //     {
        //       "order_id": "49326856",
        //       "type": "sell",
        //       "price": "1000000000",
        //       "submit_time": "1618314671",
        //       "finish_time": "1618314671",
        //       "status": "filled",
        //       "order_xrp": "30.45000000",
        //       "remain_xrp": "0.00000000"
        //     }
        //
        // cancelOrder
        //
        //    {
        //        "order_id": 666883,
        //        "client_order_id": "clientx-sj82ks82j",
        //        "type": "sell",
        //        "pair": "btc_idr",
        //        "balance": {
        //            "idr": "33605800",
        //            "btc": "0.00000000",
        //            ...
        //            "frozen_idr": "0",
        //            "frozen_btc": "0.00000000",
        //            ...
        //        }
        //    }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object side = null;
        if (Helpers.isTrue(Helpers.inOp(order, "type")))
        {
            side = Helpers.GetValue(order, "type");
        }
        Object status = this.parseOrderStatus(this.safeString(order, "status", "open"));
        Object symbol = null;
        Object cost = null;
        Object price = this.safeString(order, "price");
        Object amount = null;
        Object remaining = null;
        Object marketId = this.safeString(order, "pair");
        market = this.safeMarket(marketId, market);
        if (Helpers.isTrue(!Helpers.isEqual(market, null)))
        {
            symbol = Helpers.GetValue(market, "symbol");
            Object quoteId = Helpers.GetValue(market, "quoteId");
            Object baseId = Helpers.GetValue(market, "baseId");
            if (Helpers.isTrue(Helpers.isTrue((Helpers.isEqual(Helpers.GetValue(market, "quoteId"), "idr"))) && Helpers.isTrue((Helpers.inOp(order, "order_rp")))))
            {
                quoteId = "rp";
            }
            if (Helpers.isTrue(Helpers.isTrue((Helpers.isEqual(Helpers.GetValue(market, "baseId"), "idr"))) && Helpers.isTrue((Helpers.inOp(order, "remain_rp")))))
            {
                baseId = "rp";
            }
            cost = this.safeString(order, Helpers.add("order_", quoteId));
            if (!Helpers.isTrue(cost))
            {
                amount = this.safeString(order, Helpers.add("order_", baseId));
                remaining = this.safeString(order, Helpers.add("remain_", baseId));
            }
        }
        Object timestamp = this.safeInteger(order, "submit_time");
        Object fee = null;
        Object id = this.safeString(order, "order_id");
        final Object finalSymbol = symbol;
        final Object finalSide = side;
        final Object finalCost = cost;
        final Object finalAmount = amount;
        final Object finalRemaining = remaining;
        return this.safeOrder(new java.util.HashMap<String, Object>() {{
            put( "info", order );
            put( "id", id );
            put( "clientOrderId", IndodaxCore.this.safeString(order, "client_order_id") );
            put( "timestamp", timestamp );
            put( "datetime", IndodaxCore.this.iso8601(timestamp) );
            put( "lastTradeTimestamp", null );
            put( "symbol", finalSymbol );
            put( "type", "limit" );
            put( "timeInForce", null );
            put( "postOnly", null );
            put( "side", finalSide );
            put( "price", price );
            put( "triggerPrice", null );
            put( "cost", finalCost );
            put( "average", null );
            put( "amount", finalAmount );
            put( "filled", null );
            put( "remaining", finalRemaining );
            put( "status", status );
            put( "fee", fee );
            put( "trades", null );
        }});
    }

    /**
     * @method
     * @name indodax#fetchOrder
     * @description fetches information on an order made by the user
     * @see https://github.com/btcid/indodax-official-api-docs/blob/master/Private-RestAPI.md#get-order-endpoints
     * @param {string} id order id
     * @param {string} symbol unified symbol of the market the order was made in
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} An [order structure]{@link https://docs.ccxt.com/?id=order-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> fetchOrder(Object id, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object symbol = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            if (Helpers.isTrue(Helpers.isEqual(symbol, null)))
            {
                throw new ArgumentsRequired((String)Helpers.add(this.id, " fetchOrder() requires a symbol argument")) ;
            }
            (this.loadMarkets()).join();
            Object market = this.market(symbol);
            Object request = new java.util.HashMap<String, Object>() {{
                put( "pair", Helpers.GetValue(market, "id") );
                put( "order_id", id );
            }};
            Object response = (this.privatePostGetOrder(this.extend(request, parameters))).join();
            Object orders = Helpers.GetValue(response, "return");
            Object order = this.parseOrder(this.extend(new java.util.HashMap<String, Object>() {{
                put( "id", id );
            }}, Helpers.GetValue(orders, "order")), market);
            Helpers.addElementToObject(order, "info", response);
            return order;
        });

    }

    /**
     * @method
     * @name indodax#fetchOpenOrders
     * @description fetch all unfilled currently open orders
     * @see https://github.com/btcid/indodax-official-api-docs/blob/master/Private-RestAPI.md#open-orders-endpoints
     * @param {string} symbol unified market symbol
     * @param {int} [since] the earliest time in ms to fetch open orders for
     * @param {int} [limit] the maximum number of  open orders structures to retrieve
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {Order[]} a list of [order structures]{@link https://docs.ccxt.com/?id=order-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> fetchOpenOrders(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object symbol = Helpers.getArg(optionalArgs, 0, null);
            Object since = Helpers.getArg(optionalArgs, 1, null);
            Object limit = Helpers.getArg(optionalArgs, 2, null);
            Object parameters = Helpers.getArg(optionalArgs, 3, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object market = null;
            Object request = new java.util.HashMap<String, Object>() {{}};
            if (Helpers.isTrue(!Helpers.isEqual(symbol, null)))
            {
                market = this.market(symbol);
                Helpers.addElementToObject(request, "pair", Helpers.GetValue(market, "id"));
            }
            Object response = (this.privatePostOpenOrders(this.extend(request, parameters))).join();
            Object rawOrders = Helpers.GetValue(Helpers.GetValue(response, "return"), "orders");
            // { success: 1, return: { orders: null }} if no orders
            if (!Helpers.isTrue(rawOrders))
            {
                return new java.util.ArrayList<Object>(java.util.Arrays.asList());
            }
            // { success: 1, return: { orders: [ ... objects ] }} for orders fetched by symbol
            if (Helpers.isTrue(!Helpers.isEqual(symbol, null)))
            {
                return this.parseOrders(rawOrders, market, since, limit);
            }
            // { success: 1, return: { orders: { marketid: [ ... objects ] }}} if all orders are fetched
            Object marketIds = Helpers.objectKeys(rawOrders);
            Object exchangeOrders = new java.util.ArrayList<Object>(java.util.Arrays.asList());
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(marketIds)); i++)
            {
                Object marketId = Helpers.GetValue(marketIds, i);
                Object marketOrders = Helpers.GetValue(rawOrders, marketId);
                market = this.safeMarket(marketId);
                Object parsedOrders = this.parseOrders(marketOrders, market, since, limit);
                exchangeOrders = this.arrayConcat(exchangeOrders, parsedOrders);
            }
            return exchangeOrders;
        });

    }

